                        Text(
                            text = stringResource(country.capitalResourceId),
                            fontSize = dimensionResource(R.dimen.text_size_body).value.sp,
                            modifier = Modifier.padding(start = dimensionResource(R.dimen.padding_medium))
                        )
                        Text(
                            text = " • " + stringResource(country.codeResourceId),
                            fontSize = dimensionResource(R.dimen.text_size_body).value.sp,
                            modifier = Modifier.padding(start = dimensionResource(R.dimen.padding_small))
                        )
                    }
                }
                CountryItemButton(
                    expanded = expanded,
                    onClick = { expanded = !expanded }
                )
            }
            if (expanded) {
                Text(
                    text = stringResource(country.descriptionResourceId),
                    fontSize = dimensionResource(R.dimen.text_size_body).value.sp,
                    modifier = Modifier.padding(
                        start = dimensionResource(R.dimen.padding_medium),
                        top = dimensionResource(R.dimen.padding_small),
                        end = dimensionResource(R.dimen.padding_medium),
                        bottom = dimensionResource(R.dimen.padding_medium)
                    )
                )
            }
        }
    }
}

/**
 * Composant qui affiche le bouton pour étendre ou réduire les informations.
 */
@Composable
private fun CountryItemButton(
    expanded: Boolean,
    onClick: () -> Unit,
    modifier: Modifier = Modifier
) {
    IconButton(
        onClick = onClick,
        modifier = modifier
    ) {
        Icon(
            imageVector = if (expanded) Icons.Filled.KeyboardArrowUp else Icons.Filled.KeyboardArrowDown,
            contentDescription = stringResource(R.string.expand_button_content_description),
            tint = MaterialTheme.colorScheme.secondary
        )
    }
}

package com.example.affirmation.ui
import androidx.compose.foundation.layout.Arrangement import androidx.compose.foundation.layout.Column import androidx.compose.foundation.layout.fillMaxSize import androidx.compose.foundation.layout.padding import androidx.compose.material3.Button import androidx.compose.material3.MaterialTheme import androidx.compose.material3.Text import androidx.compose.runtime.Composable import androidx.compose.ui.Alignment import androidx.compose.ui.Modifier import androidx.compose.ui.unit.dp import androidx.navigation.NavController
@Composable fun HomeScreen(navController: NavController) { Column( modifier = Modifier .fillMaxSize() .padding(16.dp), verticalArrangement = Arrangement.Center, horizontalAlignment = Alignment.CenterHorizontally ) { Text( text = "Karibu", style = MaterialTheme.typography.displayLarge, modifier = Modifier.padding(bottom = 32.dp) ) Button( onClick = { navController.navigate("country_list") }, modifier = Modifier.padding(bottom = 16.dp) ) { Text(text = "Voir les pays") } } }

package com.example.affirmation.ui.navigation

import androidx.compose.runtime.Composable
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.compose.rememberNavController
import com.example.affirmation.ui.CountryListScreen
import com.example.affirmation.ui.HomeScreen

@Composable
fun NavigationGraph() {
    val navController = rememberNavController()
    NavHost(navController = navController, startDestination = "home") {
        composable("home") {
            HomeScreen(navController = navController)
        }
        composable("country_list") {
            CountryListScreen(navController = navController)
        }
    }
}

